// Ad-hoc test: verify MuPDF XFA parse + bind via -dbg-control TestXfa.
//
// Fixture tests/ad-hoc-xfa.pdf is generated by tests/ad-hoc-xfa.gen.py (pure-XFA
// form with two pageAreas, usehref prototypes, tb-flowed body draws, and datasets).
//
// Run:  bun tests/ad-hoc-xfa.ts [--no-build]

import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { formatXfaInfo, queryXfa } from "./xfa-test-util.ts";
import { runStandalone } from "./util.ts";

const here = dirname(fileURLToPath(import.meta.url));

export async function testit(): Promise<void> {
  const xfaPdf = join(here, "ad-hoc-xfa.pdf");
  const plainPdf = join(here, "issue-3219.pdf");

  const xfa = await queryXfa(xfaPdf);
  console.log(formatXfaInfo("ad-hoc-xfa.pdf", xfa));
  if (xfa.has_xfa !== 1) {
    throw new Error("ad-hoc-xfa.pdf: expected has_xfa=1");
  }
  if (xfa.pure_xfa !== 1) {
    throw new Error("ad-hoc-xfa.pdf: expected pure_xfa=1");
  }
  if (xfa.valid !== 1) {
    throw new Error(`ad-hoc-xfa.pdf: expected valid=1, got valid=${xfa.valid}`);
  }
  if (xfa.page_count !== 2) {
    throw new Error(`ad-hoc-xfa.pdf: expected page_count=2, got page_count=${xfa.page_count}`);
  }
  if (xfa.render_nonempty !== 1) {
    throw new Error(`ad-hoc-xfa.pdf: expected render_nonempty=1, got render_nonempty=${xfa.render_nonempty}`);
  }
  if (xfa.render_fields !== 1) {
    throw new Error(`ad-hoc-xfa.pdf: expected render_fields=1 on page 0, got render_fields=${xfa.render_fields}`);
  }
  if (xfa.render_draws !== 2) {
    throw new Error(
      `ad-hoc-xfa.pdf: expected render_draws=2 on page 0 (pageArea + flowed), got render_draws=${xfa.render_draws}`,
    );
  }
  if (xfa.render_borders !== 1) {
    throw new Error(
      `ad-hoc-xfa.pdf: expected render_borders=1 on page 0 (field border), got render_borders=${xfa.render_borders}`,
    );
  }
  if (xfa.p1_fields !== 2) {
    throw new Error(`ad-hoc-xfa.pdf: expected p1_fields=2 on page 1, got p1_fields=${xfa.p1_fields}`);
  }
  if (xfa.p1_draws !== 10) {
    throw new Error(
      `ad-hoc-xfa.pdf: expected p1_draws=10 on page 1 (pageArea + flowed + border + line + multiline + justify + tb stack), got p1_draws=${xfa.p1_draws}`,
    );
  }
  if (xfa.p1_borders !== 3) {
    throw new Error(
      `ad-hoc-xfa.pdf: expected p1_borders=3 on page 1 (field + draw + stackField), got p1_borders=${xfa.p1_borders}`,
    );
  }
  if (xfa.p1_lines !== 1) {
    throw new Error(`ad-hoc-xfa.pdf: expected p1_lines=1 on page 1, got p1_lines=${xfa.p1_lines}`);
  }
  if (xfa.serialize_ok !== 1) {
    throw new Error(`ad-hoc-xfa.pdf: expected serialize_ok=1, got serialize_ok=${xfa.serialize_ok}`);
  }
  if (xfa.serialize_bytes <= 0) {
    throw new Error(`ad-hoc-xfa.pdf: expected serialize_bytes>0, got serialize_bytes=${xfa.serialize_bytes}`);
  }

  const plain = await queryXfa(plainPdf);
  console.log(`issue-3219.pdf: has_xfa=${plain.has_xfa} valid=${plain.valid}`);
  if (plain.has_xfa !== 0) {
    throw new Error("issue-3219.pdf: expected has_xfa=0");
  }
  if (plain.valid !== 0) {
    throw new Error("issue-3219.pdf: expected valid=0");
  }
}

if (import.meta.main) {
  await runStandalone(testit);
}